mapper.insert:
INSERT INTO FACILITY_HSTRY (
RSVT_NO, CMN_FACILITY_ITEM_NO, RSVT_DT, RSVT_BGNG_DTTM, RSVT_END_DTTM,
RSVT_STTS_CD, REG_DT, MDF_DT, USER_NO, USE_PRPS_CN, USE_PRSN_CNT
) VALUES (
#{rsvtNo}, #{cmnFacilityItemNo}, TO_DATE(#{rsvtDt}, 'YYYY-MM-DD'),
TO_DATE(#{rsvtBgngDttm}, 'YYYY-MM-DD HH24:MI'), TO_DATE(#{rsvtEndDttm}, 'YYYY-MM-DD HH24:MI'),
#{rsvtSttsCd}, SYSDATE, SYSDATE, #{userNo}, #{purposeCn}, #{usePeopleCnt}
)

mapper.update:
UPDATE FACILITY_HSTRY SET RSVT_STTS_CD = 'APPROVED', MDF_DT = SYSDATE
WHERE RSVT_NO = #{rsvtNo}
AND RSVT_STTS_CD = 'PENDING'
AND CMN_FACILITY_ITEM_NO IN (
SELECT PI.CMN_FACILITY_ITEM_NO FROM PUBLIC_ITEM PI JOIN PUBLIC_FACILITY PF ON PF.CMN_FACILITY_NO = PI.CMN_FACILITY_NO
WHERE PF.APT_CMPLEX_NO = #{aptCmplexNo}
)

UPDATE FACILITY_HSTRY SET RSVT_STTS_CD = 'REJECTED', RJCT_RSN_CN = #{rejectReason}, MDF_DT = SYSDATE
WHERE RSVT_NO = #{rsvtNo}
AND RSVT_STTS_CD = 'PENDING'
AND CMN_FACILITY_ITEM_NO IN (
SELECT PI.CMN_FACILITY_ITEM_NO FROM PUBLIC_ITEM PI JOIN PUBLIC_FACILITY PF ON PF.CMN_FACILITY_NO = PI.CMN_FACILITY_NO
WHERE PF.APT_CMPLEX_NO = #{aptCmplexNo}
)

UPDATE FACILITY_HSTRY SET RSVT_STTS_CD = 'CANCELLED', MDF_DT = SYSDATE
WHERE RSVT_NO = #{rsvtNo}
AND USER_NO = #{userNo}
AND RSVT_STTS_CD IN ('PENDING','APPROVED')
AND RSVT_BGNG_DTTM > SYSDATE

mapper.select:
/* * CONNECT BY LEVEL * Oracle에서 반복 행을 만드는 문법입니다. * 여기서는 08:00~21:00까지 1시간 단위 시간표를 만듭니다. */ WITH FAC AS ( SELECT PF.CMN_FACILITY_OPR_HR, REPLACE(REGEXP_SUBSTR(PF.CMN_FACILITY_OPR_HR, '[0-9]{2}:?[0-9]{2}', 1, 1), ':', '') AS ST_TM, REPLACE(REGEXP_SUBSTR(PF.CMN_FACILITY_OPR_HR, '[0-9]{2}:?[0-9]{2}', 1, 2), ':', '') AS ED_TM FROM PUBLIC_FACILITY PF WHERE PF.APT_CMPLEX_NO = #{aptCmplexNo} AND PF.CMN_FACILITY_NO = #{searchCmnFacilityNo} ), TIME_SLOT AS ( SELECT TO_DATE(#{searchStartDt} || ' ' || SUBSTR(ST_TM,1,2) || ':' || SUBSTR(ST_TM,3,2), 'YYYY-MM-DD HH24:MI') + ((LEVEL - 1) / 24) AS BGNG_DTTM, TO_DATE(#{searchStartDt} || ' ' || SUBSTR(ST_TM,1,2) || ':' || SUBSTR(ST_TM,3,2), 'YYYY-MM-DD HH24:MI') + (LEVEL / 24) AS END_DTTM FROM FAC CONNECT BY LEVEL <= ((TO_DATE(ED_TM, 'HH24MI') - TO_DATE(ST_TM, 'HH24MI')) * 24) ) SELECT TO_CHAR(TS.BGNG_DTTM, 'HH24:MI') || ' ~ ' || TO_CHAR(TS.END_DTTM, 'HH24:MI') AS TIME_LABEL, TO_CHAR(TS.BGNG_DTTM, 'YYYY-MM-DD HH24:MI') AS RSVT_BGNG_DTTM, TO_CHAR(TS.END_DTTM, 'YYYY-MM-DD HH24:MI') AS RSVT_END_DTTM, FH.RSVT_NO, #{searchItemNo} AS CMN_FACILITY_ITEM_NO, M.USER_NM, CASE WHEN FH.RSVT_NO IS NOT NULL THEN 'Y'
WHEN EXISTS ( SELECT 1 FROM FACILITY_CHECK_HSTRY FCH JOIN PUBLIC_FACILITY TPF ON TPF.FACILITY_NO = FCH.FACILITY_NO WHERE TPF.APT_CMPLEX_NO = #{aptCmplexNo} AND TPF.CMN_FACILITY_NO = #{searchCmnFacilityNo} AND NVL(FCH.USE_RESTRICT_YN, 'N') = 'Y' AND FCH.USE_RESTRICT_BGNG_DT IS NOT NULL AND FCH.USE_RESTRICT_END_DT IS NOT NULL AND FCH.USE_RESTRICT_BGNG_DT < TS.END_DTTM AND FCH.USE_RESTRICT_END_DT > TS.BGNG_DTTM ) THEN 'Y' ELSE 'N' END AS RESERVED_YN, CASE WHEN FH.RSVT_NO IS NOT NULL THEN '예약완료'
WHEN EXISTS ( SELECT 1 FROM FACILITY_CHECK_HSTRY FCH JOIN PUBLIC_FACILITY TPF ON TPF.FACILITY_NO = FCH.FACILITY_NO WHERE TPF.APT_CMPLEX_NO = #{aptCmplexNo} AND TPF.CMN_FACILITY_NO = #{searchCmnFacilityNo} AND NVL(FCH.USE_RESTRICT_YN, 'N') = 'Y' AND FCH.USE_RESTRICT_BGNG_DT IS NOT NULL AND FCH.USE_RESTRICT_END_DT IS NOT NULL AND FCH.USE_RESTRICT_BGNG_DT < TS.END_DTTM AND FCH.USE_RESTRICT_END_DT > TS.BGNG_DTTM ) THEN '점검중' ELSE '예약가능' END AS RSVT_STTS_NM FROM TIME_SLOT TS LEFT JOIN FACILITY_HSTRY FH ON FH.CMN_FACILITY_ITEM_NO = #{searchItemNo} AND FH.RSVT_STTS_CD IN ('PENDING', 'APPROVED') AND FH.RSVT_BGNG_DTTM < TS.END_DTTM AND FH.RSVT_END_DTTM > TS.BGNG_DTTM LEFT JOIN MEMBER M ON M.USER_NO = FH.USER_NO ORDER BY TS.BGNG_DTTM

